customCSS:
/* ===== GLOBAL STYLES ===== */
body {
    font-family: "Salesforce Sans", Arial, sans-serif;
    color: #181818;
    background-color: #FFFFFF;
    font-size: 16px;
}

/* ===== HEADINGS ===== */
h1, h2, h3 {
    font-weight: 600;
    color: #032D60;
}

h1 { font-size: 46px; }
h2 { font-size: 28px; }
h3 { font-size: 20px; }

/* ===== BUTTONS ===== */
.slds-button {
    border-radius: 6px !important;
    padding: 10px 20px !important;
    font-weight: 500;
}

.slds-button_brand {
    background-color: #0176D3 !important;
    border-color: #0176D3 !important;
}

.slds-button_brand:hover {
    background-color: #014486 !important;
}

/* ===== CARD STYLE ===== */
.custom-card {
    border-radius: 12px;
    padding: 20px;
    background: #FFFFFF;
    border: 1px solid #E5E5E5;
    box-shadow: 0 2px 6px rgba(0,0,0,0.05);
    transition: all 0.2s ease;
}

.custom-card:hover {
    box-shadow: 0 4px 12px rgba(1, 118, 211, 0.15);
    transform: translateY(-3px);
}

/* ===== DEPARTMENT COLORS ===== */
.oncology { border-left: 4px solid #0176D3; }
.gynecology { border-left: 4px solid #BA0517; }
.pediatrics { border-left: 4px solid #2E844A; }

/* ===== SECTION SPACING ===== */
.section-padding {
    padding: 50px 20px;
}

/* ===== HERO SECTION ===== */
.hero {
    background: linear-gradient(to right, #0176D3, #032D60);
    color: white;
    padding: 80px 20px;
}

.hero h1 {
    color: white;
}

.hero-container {
    display: flex;
    align-items: center;
    justify-content: space-between;
    max-width: 1100px;
    margin: auto;
    gap: 40px;
}

/* ===== TEXT SIDE ===== */
.hero-text {
    flex: 1;
    font-size: 18px;
}

.hero-text h1 {
    font-size: 42px;
    line-height: 1.3;
    margin-top: 10px;
}

.title {
    font-size: 18px;
    opacity: 0.9;
}

.highlight {
    color: #FFFFFF;
    font-weight: 700;
}

/* ===== IMAGE SIDE ===== */
.hero-image {
    flex: 1;
    text-align: right;
    position: relative; /* 🔥 IMPORTANT for overlay */
}

.hero-image img {
    max-width: 300px;
    border-radius: 12px;
    position: relative;
    z-index: 1;
}

/* ===== ⭐ REVIEW OVER IMAGE (UPDATED) ===== */
.review-card {
    position: absolute;
    bottom: 20px;
    left: -60px; /* overlap towards text */

    background: rgba(255, 255, 255, 0.95);
    color: #032D60;

    padding: 15px 18px;
    border-radius: 10px;
    width: 260px;

    box-shadow: 0 8px 20px rgba(0,0,0,0.15);
    backdrop-filter: blur(6px);

    z-index: 2;
}

.review-text {
    font-size: 14px;
    font-style: italic;
    margin-bottom: 8px;
}

.review-user {
    font-size: 13px;
    font-weight: 500;
    opacity: 0.9;
}

/* ===== NAVBAR ===== */
header {
    background: #FFFFFF;
    border-bottom: 1px solid #E5E5E5;
}

/* ===== TILES ===== */
.tiles-container {
    display: flex;
    gap: 20px;
    flex-wrap: wrap;
    max-width: 1100px;
    margin: 40px auto;
}

.tile {
    flex: 1;
    background: #F3F9FF;
    padding: 20px;
    border-radius: 12px;
    border: 1px solid #E5E5E5;
    min-height: 120px;
    display: flex;
    align-items: center;
    transition: all 0.2s ease;
}

.tile.big {
    border-left: 4px solid #0176D3;
}

.big {
    font-size: 22px;
    font-weight: 600;
    color: #032D60;
}

.small {
    font-size: 16px;
    color: #181818;
}

.tile:hover {
    box-shadow: 0 4px 12px rgba(1, 118, 211, 0.15);
}

/* ===== TREATMENT SECTION ===== */
.treatment-section {
    text-align: center;
    margin: 60px auto;
    max-width: 1100px;
}

.treatment-heading {
    font-size: 26px;
    font-weight: 600;
    color: #032D60;
    margin-bottom: 35px;
}

.treatment-container {
    display: flex;
    justify-content: center;
    gap: 20px;
    flex-wrap: wrap;
}

.treatment-card {
    background: #F3F9FF;
    padding: 25px 20px;
    border-radius: 14px;
    width: 240px;
    text-align: center;
    border: 1px solid #E5E5E5;
    transition: all 0.25s ease;
}

/* ===== ICON ===== */
.treatment-icon {
    width: 60px;
    height: 60px;
    margin-bottom: 15px;
    padding: 12px;
    background: #0176D3;
    border-radius: 50%;
    object-fit: contain;
}

.treatment-card h3 {
    font-size: 18px;
    margin-bottom: 8px;
}

.sub-text {
    font-size: 14px;
    color: #5F6A7D;
    margin-bottom: 12px;
}

.underline {
    width: 40px;
    height: 2px;
    background: #0176D3;
    margin: auto;
    border-radius: 5px;
}

.treatment-card:hover {
    box-shadow: 0 6px 16px rgba(1, 118, 211, 0.2);
    transform: translateY(-5px);
}

.treatment-card:hover .treatment-icon {
    transform: scale(1.1);
    transition: 0.3s ease;
}

/* ===== MOBILE ===== */
@media (max-width: 768px) {
    .tiles-container {
        flex-direction: column;
        padding: 0 15px;
    }

    .hero-container {
        flex-direction: column;
        text-align: center;
    }

    .hero-image {
        margin-top: 20px;
        text-align: center;
    }

    /* center review on mobile */
    .review-card {
        position: static;
        margin-top: 15px;
        width: auto;
    }

    .treatment-container {
        flex-direction: column;
        align-items: center;
    }
}
